// Import necessary libraries
const Web3 = require('web3');
const { ethers } = require('ethers');

// Initialize web3 provider
const provider = new Web3(new Web3.providers.HttpProvider('your-rpc-url'));

// Define wallet configuration
const privateKey = 'your-private-key';
const wallet = new ethers.Wallet(privateKey, provider);

// Function to send ETH
async function sendEth(toAddress, amount) {
  const transaction = {
    from: wallet.address,
    to: toAddress,
    value: ethers.utils.parseEther(amount.toString()),
    gasPrice: await provider.getGasPrice(),
    gasLimit: 21000,
  };

  const signedTransaction = await wallet.signTransaction(transaction);
  const transactionHash = await provider.sendTransaction(signedTransaction);

  console.log(`Transaction hash: ${transactionHash}`);
}

// Function to interact with smart contract
async function interactWithContract(contractAddress, abi, functionName, ...args) {
  const contract = new ethers.Contract(contractAddress, abi, wallet);
  const transaction = await contract[functionName](...args);
  await transaction.wait();

  console.log(`Smart contract function executed successfully.`);
}

// Example usage
sendEth('recipient-address', 0.1);
interactWithContract('contract-address', ['abi'], 'functionName', 'arg1', 'arg2');